import{_ as l,o as e,c as t,ag as i}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Hapi 进阶配置：Cloudflare 优选 IP 高速穿透","description":"","frontmatter":{},"headers":[],"relativePath":"apps/hapi-advanced.md","filePath":"apps/hapi-advanced.md"}'),d={name:"apps/hapi-advanced.md"};function o(n,a,s,p,h,r){return e(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="hapi-进阶配置-cloudflare-优选-ip-高速穿透" tabindex="-1">Hapi 进阶配置：Cloudflare 优选 IP 高速穿透 <a class="header-anchor" href="#hapi-进阶配置-cloudflare-优选-ip-高速穿透" aria-label="Permalink to &quot;Hapi 进阶配置：Cloudflare 优选 IP 高速穿透&quot;">​</a></h1><p>没有公网 IP？使用 Cloudflare 优选 IP，打造高速内网穿透通道</p><p>适用场景：已配置 Cloudflare Tunnel，但访问速度慢、延迟高 解决方案：利用 Cloudflare for SaaS + 优选 IP 服务，绕过拥堵节点 前置要求：已完成 <a href="/apps/hapi">Hapi 基础配置</a>，拥有两个域名</p><h2 id="视频教程" tabindex="-1">视频教程 <a class="header-anchor" href="#视频教程" aria-label="Permalink to &quot;视频教程&quot;">​</a></h2><p>推荐观看</p><p>视频详细演示了完整的配置过程，强烈建议先观看视频再进行操作。</p><h2 id="你正在解决什么问题" tabindex="-1">你正在解决什么问题？ <a class="header-anchor" href="#你正在解决什么问题" aria-label="Permalink to &quot;你正在解决什么问题？&quot;">​</a></h2><h3 id="默认-tunnel-的痛点" tabindex="-1">默认 Tunnel 的痛点 <a class="header-anchor" href="#默认-tunnel-的痛点" aria-label="Permalink to &quot;默认 Tunnel 的痛点&quot;">​</a></h3><p>当你直接使用 Cloudflare Tunnel 绑定域名时：</p><ul><li>❌ Cloudflare 分配的 Anycast IP 在国内可能被绕路（绕到美国、欧洲）</li><li>❌ 运营商 QoS 限速，访问速度慢</li><li>❌ 延迟高达几百毫秒，严重影响使用体验</li></ul><h3 id="优选-ip-方案的优势" tabindex="-1">优选 IP 方案的优势 <a class="header-anchor" href="#优选-ip-方案的优势" aria-label="Permalink to &quot;优选 IP 方案的优势&quot;">​</a></h3><p>通过本教程的配置：</p><ul><li>✅ 强制流量走对国内网络友好的节点（香港、新加坡等）</li><li>✅ 大幅提升访问速度，延迟降低到几十毫秒</li><li>✅ 完全免费，利用 Cloudflare 企业级功能</li><li>✅ 稳定性高，自动切换最优路由</li></ul><p>🚀 速度提升对比</p><p>优选 IP 后访问速度得到了显著提升，延迟从几百毫秒降低到几十毫秒，页面加载也更加流畅！</p><h2 id="原理解析" tabindex="-1">原理解析 <a class="header-anchor" href="#原理解析" aria-label="Permalink to &quot;原理解析&quot;">​</a></h2><h3 id="流量走向链路" tabindex="-1">流量走向链路 <a class="header-anchor" href="#流量走向链路" aria-label="Permalink to &quot;流量走向链路&quot;">​</a></h3><p>当用户访问你的域名时，流量是这样流转的：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户浏览器</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>DNS 解析：hapi.justdo.xin</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>CNAME → cdn.ttdk.fun</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>CNAME → isp.qzz.io（优选 IP 调度器）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>返回最优 Cloudflare IP（根据用户运营商）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Cloudflare 边缘节点（通过 Host Header 识别）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>SaaS 路由：hapi.justdo.xin → hapi.ttdk.fun</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Cloudflare Tunnel（加密隧道）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>你的本地服务器 localhost:3006</span></span></code></pre></div><h3 id="核心技术要点" tabindex="-1">核心技术要点 <a class="header-anchor" href="#核心技术要点" aria-label="Permalink to &quot;核心技术要点&quot;">​</a></h3><p>优选 IP 调度器：isp.qzz.io 会根据用户的网络环境（电信/联通/移动），返回当前速度最快、延迟最低的 Cloudflare 官方 CDN 节点 IP</p><p>Cloudflare for SaaS：通过 Custom Hostnames 功能，把&quot;访问域名&quot;和&quot;隧道域名&quot;解耦，实现&quot;走优选 IP 进隧道&quot;</p><p>DNS 链式解析：通过 CNAME 链，把用户请求引导到优选 IP，同时保持 Cloudflare 对域名的正确识别</p><p>💡 关于优选 IP 调度器</p><p>isp.qzz.io 是一个社区维护的 Cloudflare 优选 IP 调度服务，它会自动测速并返回对你当前网络环境最优的 Cloudflare CDN 节点。访问该网站可以查看更多信息和使用说明。</p><h2 id="配置步骤" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤" aria-label="Permalink to &quot;配置步骤&quot;">​</a></h2><h3 id="前置准备" tabindex="-1">前置准备 <a class="header-anchor" href="#前置准备" aria-label="Permalink to &quot;前置准备&quot;">​</a></h3><p>你需要准备：</p><ol><li>主力域名：用于展示给用户访问（例如：<code>hapi.justdo.xin</code>）</li><li>辅助域名：用于承载 Cloudflare Tunnel（例如：<code>ttdk.fun</code>）</li><li>两个域名都需要托管在 Cloudflare</li></ol><p>⚠️ 重要说明</p><ul><li>主力域名和辅助域名不能是同一个域名</li><li>辅助域名需要是你自己拥有的，不能用别人的</li><li>两个域名都必须在 Cloudflare 上管理</li></ul><h3 id="第一步-配置-cloudflare-tunnel-辅助域名" tabindex="-1">第一步：配置 Cloudflare Tunnel（辅助域名） <a class="header-anchor" href="#第一步-配置-cloudflare-tunnel-辅助域名" aria-label="Permalink to &quot;第一步：配置 Cloudflare Tunnel（辅助域名）&quot;">​</a></h3><p>在辅助域名（例如 <code>ttdk.fun</code>）上设置 Tunnel：</p><p>配置公共主机名：</p><ul><li>子域名：<code>hapi</code></li><li>域名：<code>ttdk.fun</code></li><li>服务：<code>http://localhost:3006</code></li></ul><p>完成后你应该能通过 <code>hapi.ttdk.fun</code> 访问你的 Hapi 服务。</p><h3 id="第二步-启用-cloudflare-for-saas-辅助域名" tabindex="-1">第二步：启用 Cloudflare for SaaS（辅助域名） <a class="header-anchor" href="#第二步-启用-cloudflare-for-saas-辅助域名" aria-label="Permalink to &quot;第二步：启用 Cloudflare for SaaS（辅助域名）&quot;">​</a></h3><p>在辅助域名（<code>ttdk.fun</code>）上启用 SaaS 功能：</p><p>填写：</p><ul><li>Custom Hostname：<code>hapi.justdo.xin</code>（主力域名）</li><li>Wildcard：不勾选</li></ul><p>💡 提示</p><p>添加后会生成 2 条 TXT 验证记录，先不着急配置，继续下一步。</p><h3 id="第三步-配置-dns-解析-主力域名" tabindex="-1">第三步：配置 DNS 解析（主力域名） <a class="header-anchor" href="#第三步-配置-dns-解析-主力域名" aria-label="Permalink to &quot;第三步：配置 DNS 解析（主力域名）&quot;">​</a></h3><p>在主力域名（<code>justdo.xin</code>）的 DNS 设置中添加以下记录：</p><h4 id="_3-1-添加-ssl-验证记录" tabindex="-1">3.1 添加 SSL 验证记录 <a class="header-anchor" href="#_3-1-添加-ssl-验证记录" aria-label="Permalink to &quot;3.1 添加 SSL 验证记录&quot;">​</a></h4><p>从第二步中复制 Cloudflare 生成的 2 条 TXT 记录，添加到主力域名的 DNS：</p><table tabindex="0"><thead><tr><th>类型</th><th>名称</th><th>内容</th><th>代理状态</th></tr></thead><tbody><tr><td>TXT</td><td><code>_acme-challenge.hapi</code></td><td><code>xxxxxxxxxx</code>（从 SaaS 页面复制）</td><td>仅限 DNS</td></tr><tr><td>TXT</td><td><code>_acme-challenge.hapi</code></td><td><code>yyyyyyyyyy</code>（从 SaaS 页面复制）</td><td>仅限 DNS</td></tr></tbody></table><h4 id="_3-2-添加-cname-记录" tabindex="-1">3.2 添加 CNAME 记录 <a class="header-anchor" href="#_3-2-添加-cname-记录" aria-label="Permalink to &quot;3.2 添加 CNAME 记录&quot;">​</a></h4><table tabindex="0"><thead><tr><th>类型</th><th>名称</th><th>目标</th><th>代理状态</th></tr></thead><tbody><tr><td>CNAME</td><td><code>cdn</code></td><td><code>isp.qzz.io</code></td><td>仅限 DNS ⚠️</td></tr><tr><td>CNAME</td><td><code>hapi</code></td><td><code>cdn.justdo.xin</code></td><td>仅限 DNS ⚠️</td></tr></tbody></table><p>🚨 关键配置</p><p>必须关闭小黄云（代理状态设为&quot;仅限 DNS&quot;）！</p><p>如果开启代理，会导致 DNS 解析链中断，无法触发优选 IP。</p><h3 id="第四步-配置回退源-辅助域名" tabindex="-1">第四步：配置回退源（辅助域名） <a class="header-anchor" href="#第四步-配置回退源-辅助域名" aria-label="Permalink to &quot;第四步：配置回退源（辅助域名）&quot;">​</a></h3><p>在辅助域名（<code>ttdk.fun</code>）的 DNS 设置中：</p><table tabindex="0"><thead><tr><th>类型</th><th>名称</th><th>目标</th><th>代理状态</th></tr></thead><tbody><tr><td>CNAME</td><td><code>hapi</code></td><td><code>[你的隧道ID].cfargotunnel.com</code></td><td>已代理 ✅</td></tr></tbody></table><p>💡 提示</p><p>这条记录通常在创建 Tunnel 时自动生成。确保小黄云是开启状态（已代理）。</p><h3 id="第五步-等待-ssl-证书生效" tabindex="-1">第五步：等待 SSL 证书生效 <a class="header-anchor" href="#第五步-等待-ssl-证书生效" aria-label="Permalink to &quot;第五步：等待 SSL 证书生效&quot;">​</a></h3><ol><li>点击 Add Custom Hostname</li><li>回到辅助域名的 SSL/TLS → Custom Hostnames 页面</li><li>查看 <code>hapi.justdo.xin</code> 的状态</li><li>等待几分钟，状态变为 Active（有效）即表示配置成功</li></ol><p>⏳ 耐心等待</p><p>SSL 证书签发通常需要 5-15 分钟，请耐心等待。如果超过 30 分钟仍未生效，检查 TXT 记录是否正确添加。</p><h2 id="验证配置" tabindex="-1">验证配置 <a class="header-anchor" href="#验证配置" aria-label="Permalink to &quot;验证配置&quot;">​</a></h2><h3 id="测试访问" tabindex="-1">测试访问 <a class="header-anchor" href="#测试访问" aria-label="Permalink to &quot;测试访问&quot;">​</a></h3><p>在浏览器中访问：<code>https://hapi.justdo.xin</code></p><p>如果能正常打开 Hapi 界面，说明配置成功！</p><h3 id="测试速度提升" tabindex="-1">测试速度提升 <a class="header-anchor" href="#测试速度提升" aria-label="Permalink to &quot;测试速度提升&quot;">​</a></h3><p>使用 ping 或测速工具对比：</p><p>优化前：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hapi.ttdk.fun</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 延迟通常 200-500ms</span></span></code></pre></div><p>优化后：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hapi.justdo.xin</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 延迟通常 20-100ms</span></span></code></pre></div><h2 id="角色分配总结" tabindex="-1">角色分配总结 <a class="header-anchor" href="#角色分配总结" aria-label="Permalink to &quot;角色分配总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>域名示例</th><th>作用</th></tr></thead><tbody><tr><td>主力域名</td><td><code>hapi.justdo.xin</code></td><td>你最终展示给用户访问的地址</td></tr><tr><td>辅助域名</td><td><code>hapi.ttdk.fun</code></td><td>承载 Tunnel 的&quot;回退源&quot;，用户不直接感知</td></tr><tr><td>优选 IP 调度器</td><td>isp.qzz.io</td><td>像&quot;交警&quot;，告诉流量该走哪条不堵的路</td></tr><tr><td>中转域名</td><td><code>cdn.justdo.xin</code></td><td>作为跳板，把主力域名引向优选 IP 池</td></tr></tbody></table><h2 id="故障排查" tabindex="-1">故障排查 <a class="header-anchor" href="#故障排查" aria-label="Permalink to &quot;故障排查&quot;">​</a></h2><h3 id="ssl-证书一直显示-pending" tabindex="-1">SSL 证书一直显示 Pending？ <a class="header-anchor" href="#ssl-证书一直显示-pending" aria-label="Permalink to &quot;SSL 证书一直显示 Pending？&quot;">​</a></h3><p>可能原因：</p><ul><li>TXT 记录添加错误或未生效</li><li>DNS 传播未完成</li></ul><p>解决方法：</p><ol><li>使用 DNS 检查工具验证 TXT 记录</li><li>等待 DNS 全球传播（最多 24 小时）</li><li>重新添加 Custom Hostname</li></ol><h3 id="访问显示-526-错误" tabindex="-1">访问显示 526 错误？ <a class="header-anchor" href="#访问显示-526-错误" aria-label="Permalink to &quot;访问显示 526 错误？&quot;">​</a></h3><p>可能原因：</p><ul><li>辅助域名的 <code>hapi</code> 记录未开启代理（小黄云）</li><li>Tunnel 未正确配置</li></ul><p>解决方法：</p><ol><li>确保 <code>hapi.ttdk.fun</code> 的小黄云是开启状态</li><li>检查 Tunnel 是否正常运行</li></ol><h3 id="访问仍然很慢" tabindex="-1">访问仍然很慢？ <a class="header-anchor" href="#访问仍然很慢" aria-label="Permalink to &quot;访问仍然很慢？&quot;">​</a></h3><p>可能原因：</p><ul><li>主力域名的 CNAME 记录开启了代理</li><li>DNS 解析链断裂</li></ul><p>解决方法：</p><ol><li>确保 <code>hapi.justdo.xin</code> 和 <code>cdn.justdo.xin</code> 的小黄云都是关闭状态</li><li>使用 <code>nslookup</code> 检查 DNS 解析链是否完整</li></ol><h2 id="进阶优化" tabindex="-1">进阶优化 <a class="header-anchor" href="#进阶优化" aria-label="Permalink to &quot;进阶优化&quot;">​</a></h2><h3 id="自建优选-ip-服务" tabindex="-1">自建优选 IP 服务 <a class="header-anchor" href="#自建优选-ip-服务" aria-label="Permalink to &quot;自建优选 IP 服务&quot;">​</a></h3><p>如果你追求极致稳定，可以：</p><ol><li>使用 CloudflareSpeedTest 工具本地测速</li><li>手动选择最优 IP</li><li>创建自己的优选域名，替代 <code>isp.qzz.io</code></li></ol><h3 id="多运营商优化" tabindex="-1">多运营商优化 <a class="header-anchor" href="#多运营商优化" aria-label="Permalink to &quot;多运营商优化&quot;">​</a></h3><p>可以针对不同运营商配置不同的优选路径：</p><ul><li>电信用户：<code>cdn-ct.yourdomain.com</code></li><li>联通用户：<code>cdn-cu.yourdomain.com</code></li><li>移动用户：<code>cdn-cm.yourdomain.com</code></li></ul><p>通过 DNS 智能解析（GeoDNS），根据用户运营商返回不同的 CNAME 记录。</p><h2 id="相关资源" tabindex="-1">相关资源 <a class="header-anchor" href="#相关资源" aria-label="Permalink to &quot;相关资源&quot;">​</a></h2><ul><li>Cloudflare for SaaS 官方文档</li><li>Cloudflare Tunnel 文档</li><li>isp.qzz.io - 优选 IP 调度器</li><li>视频教程：cloudflare 优选 IP 配置</li></ul><h2 id="安全提醒" tabindex="-1">安全提醒 <a class="header-anchor" href="#安全提醒" aria-label="Permalink to &quot;安全提醒&quot;">​</a></h2><ol><li>不要泄露你的 Tunnel 令牌</li><li>定期检查 Custom Hostnames 配置</li><li>isp.qzz.io 是社区维护的优选 IP 服务，虽然可靠但非官方服务，你也可以选择自建优选服务</li><li>建议配合 Cloudflare Access 限制访问来源</li></ol><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>通过这套配置，你：</p><ul><li>✅ 不花一分钱</li><li>✅ 利用 Cloudflare 企业级 SaaS 功能</li><li>✅ 把原本几百毫秒延迟的内网穿透，优化到接近直连的体验</li><li>✅ 打造了一条&quot;高速内网穿透通道&quot;</li></ul><p>这就是目前免费方案中，提升 Cloudflare 内网穿透速度的天花板级别配置！</p><hr><p>下一步：配置完成后，你可以愉快地在任何地方高速访问你的 Hapi 服务了！🎉</p>`,107)])])}const b=l(d,[["render",o]]);export{u as __pageData,b as default};
